  ('elementary-0a2fc18c-moex-00950', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '有關消費者無異曲線之敘述，下列何者正確？', '["所得增加會造成無異曲線平行外移", "無異曲線上任一點的切線斜率稱為邊際轉換率", "不同的無異曲線可能對應相同的滿足水準", "當兩消費財貨彼此間完全替代時，無異曲線為直線"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00951', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '若一消費者的效用函數為U(X,Y)=XY，其中X與Y為兩種財貨消費數量，若兩產品之價格相等，則在消 費者效用極大之最適消費組合點，下列那一個條件不成立？', '["兩種產品之邊際效用相等", "兩種產品之支出相等", "兩種產品之消費量相等", "兩種產品之支出不相等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
